  1  /**
  2   * @file main.c
  3   * @brief ILI9488 Color Fill Demo
  4   *
  5   * Cycles through solid colors on a 320x480 ILI9488 display connected to a Raspberry Pi 4B via SPI0:
  6   *   SPI device : /dev/spidev0.0  (10 MHz)
  7   *   RESET GPIO : BCM 24 (Pin 18)
  8   *   D/C GPIO   : BCM 25 (Pin 22)
  9   *   CS         : BCM  8 / SPI0_CE0 (Pin 24) -- handled by spidev
 10   *
 11   * AI Usage Disclaimer: This file was mostly outlined then generated using AI tools. See ./AI_chats for the full conversation logs as best as could be exported.
 12   */
 13
 14   // Note: Next ToDo: Update demo to use framebuffer API, doing a dirty region animation with color changes to show smearing and moving in a square
 15   // Also ToDo: Add something to do the single pixel draw demo
 16   // After ToDo: Add Line drawing to demo
 17   // Then ToDo: Add text drawing library, then add text to demo
 18   // Final ToDo: Review and clean up all code, finalize comments and documentation (readme and wiki), and prepare for final project submission
 19
 20  #include "ili9488_gfx.h"
 21  #include "ili9488_hal.h"
 22  #include <stdio.h>
 23  #include <stdlib.h>
 24  #include <unistd.h>
 25
 26
 27  /* RGB565 color values */
 28  #define COLOR_RED     0xF800U
 29  #define COLOR_GREEN   0x07E0U
 30  #define COLOR_BLUE    0x001FU
 31  #define COLOR_WHITE   0xFFFFU
 32  #define COLOR_BLACK   0x0000U
 33  #define COLOR_YELLOW  0xFFE0U
 34  #define COLOR_CYAN    0x07FFU
 35  #define COLOR_MAGENTA 0xF81FU
 36
 37  #define DISPLAY_WIDTH  ILI9488_GFX_DEFAULT_WIDTH
 38  #define DISPLAY_HEIGHT ILI9488_GFX_DEFAULT_HEIGHT
 39
 40  #define FRAME_DELAY_MS 95U
 41  #define DIRTY_BOX_SIZE 105U
 42  #define PATH_MARGIN    24U
 43  #define STEP_PIXELS    8U
 44
 45  #define FULL_FILL_INTERVAL_FRAMES 120U
 46  #define FULL_FILL_HOLD_MS         170U
 47  #define FULL_FILL_SHOW_COUNT      3U
 48
 49  typedef enum {
 50      MOVE_RIGHT = 0,
 51      MOVE_DOWN,
 52      MOVE_LEFT,
 53      MOVE_UP
 54  } move_direction_t;
 55
 56  int main(void)
 57  {
 58      printf("ILI9488 Demo\n");
 59
 60      if (!hal_display_initialize(PIXEL_FORMAT_18BIT, ROTATION_0_NORMAL)) {
 61          fprintf(stderr, "Error: display initialisation failed\n");
 62          return EXIT_FAILURE;
 63      }
 64
 65      printf("Display ready -- starting dirty-region smear demo\n");
 66
 67      size_t fb_pixels = gfx_framebuffer_required_pixels(DISPLAY_WIDTH, DISPLAY_HEIGHT);
 68      if (fb_pixels == 0U) {
 69          fprintf(stderr, "Error: invalid framebuffer dimensions\n");
 70          hal_display_deinitialize();
 71          return EXIT_FAILURE;
 72      }
 73
 74      uint16_t *fb_storage = (uint16_t *)malloc(fb_pixels * sizeof(uint16_t));
 75      if (fb_storage == NULL) {
 76          fprintf(stderr, "Error: framebuffer allocation failed\n");
 77          hal_display_deinitialize();
 78          return EXIT_FAILURE;
 79      }
 80
 81      gfx_framebuffer_t framebuffer;
 82      if (!gfx_framebuffer_bind(&framebuffer,
 83                                fb_storage,
 84                                fb_pixels,
 85                                DISPLAY_WIDTH,
 86                                DISPLAY_HEIGHT,
 87                                0U)) {
 88          fprintf(stderr, "Error: framebuffer bind failed\n");
 89          free(fb_storage);
 90          hal_display_deinitialize();
 91          return EXIT_FAILURE;
 92      }
 93
 94      if (!gfx_fill(&framebuffer, COLOR_BLACK) || !gfx_flush(&framebuffer)) {
 95          fprintf(stderr, "Error: initial framebuffer clear/flush failed\n");
 96          gfx_framebuffer_unbind(&framebuffer);
 97          free(fb_storage);
 98          hal_display_deinitialize();
 99          return EXIT_FAILURE;
100      }
101
102      static const struct {
103          uint16_t    color;
104          const char *name;
105      } colors[] = {
106          { COLOR_RED,     "Red"     },
107          { COLOR_GREEN,   "Green"   },
108          { COLOR_BLUE,    "Blue"    },
109          { COLOR_WHITE,   "White"   },
110          { COLOR_BLACK,   "Black"   },
111          { COLOR_YELLOW,  "Yellow"  },
112          { COLOR_CYAN,    "Cyan"    },
113          { COLOR_MAGENTA, "Magenta" }
114      };
115
116      int color_count = (int)(sizeof(colors) / sizeof(colors[0]));
117
118      uint16_t path_left = PATH_MARGIN;
119      uint16_t path_top = PATH_MARGIN;
120      uint16_t path_right = DISPLAY_WIDTH - PATH_MARGIN - DIRTY_BOX_SIZE;
121      uint16_t path_bottom = DISPLAY_HEIGHT - PATH_MARGIN - DIRTY_BOX_SIZE;
122
123      if (path_right <= path_left || path_bottom <= path_top) {
124          fprintf(stderr, "Error: dirty region path does not fit display\n");
125          gfx_framebuffer_unbind(&framebuffer);
126          free(fb_storage);
127          hal_display_deinitialize();
128          return EXIT_FAILURE;
129      }
130
131      uint16_t box_x = path_left;
132      uint16_t box_y = path_top;
133      int color_index = 0;
134      int pixel_color_index = 0;
135      move_direction_t direction = MOVE_RIGHT;
136
137      uint16_t pixel_x = DISPLAY_WIDTH / 2U;
138      uint16_t pixel_y = DISPLAY_HEIGHT / 2U;
139      int16_t pixel_dx = (int16_t)STEP_PIXELS;
140      int16_t pixel_dy = (int16_t)STEP_PIXELS;
141      unsigned int frame_count = 0U;
142
143      while (1) {
144          if (frame_count > 0U && (frame_count % FULL_FILL_INTERVAL_FRAMES) == 0U) {
145              unsigned int full_fill_index;
146              for (full_fill_index = 0U; full_fill_index < FULL_FILL_SHOW_COUNT; full_fill_index++) {
147                  int fill_color_index = (color_index + (int)full_fill_index) % color_count;
148                  printf("  Full fill: %s\n", colors[fill_color_index].name);
149                  if (!gfx_fill(&framebuffer, colors[fill_color_index].color) || !gfx_flush(&framebuffer)) {
150                      fprintf(stderr, "Error: full-screen fill failed while drawing %s\n", colors[fill_color_index].name);
151                      gfx_framebuffer_unbind(&framebuffer);
152                      free(fb_storage);
153                      hal_display_deinitialize();
154                      return EXIT_FAILURE;
155                  }
156                  usleep(FULL_FILL_HOLD_MS * 1000U);
157              }
158          }
159
160          uint16_t box_x2 = box_x + DIRTY_BOX_SIZE - 1U;
161          uint16_t box_y2 = box_y + DIRTY_BOX_SIZE - 1U;
162
163          if (!gfx_draw_filled_rectangle(&framebuffer, box_x, box_y, box_x2, box_y2, colors[color_index].color)) {
164              fprintf(stderr, "Error: framebuffer draw failed while drawing %s\n", colors[color_index].name);
165              gfx_framebuffer_unbind(&framebuffer);
166              free(fb_storage);
167              hal_display_deinitialize();
168              return EXIT_FAILURE;
169          }
170
171          if (!gfx_flush_dirty(&framebuffer)) {
172              fprintf(stderr, "Error: dirty flush failed while drawing %s\n", colors[color_index].name);
173              gfx_framebuffer_unbind(&framebuffer);
174              free(fb_storage);
175              hal_display_deinitialize();
176              return EXIT_FAILURE;
177          }
178
179          /* Single pixel demo: moving pixel that bounces across the full display. */
180          if (!gfx_draw_pixel(&framebuffer, pixel_x, pixel_y, colors[pixel_color_index].color)) {
181              fprintf(stderr, "Error: single-pixel draw failed at (%u,%u)\n", pixel_x, pixel_y);
182              gfx_framebuffer_unbind(&framebuffer);
183              free(fb_storage);
184              hal_display_deinitialize();
185              return EXIT_FAILURE;
186          }
187
188          if (!gfx_flush_dirty(&framebuffer)) {
189              fprintf(stderr, "Error: dirty flush failed during single-pixel draw\n");
190              gfx_framebuffer_unbind(&framebuffer);
191              free(fb_storage);
192              hal_display_deinitialize();
193              return EXIT_FAILURE;
194          }
195
196          color_index = (color_index + 1) % color_count;
197          pixel_color_index = (pixel_color_index + 1) % color_count;
198
199          switch (direction) {
200          case MOVE_RIGHT:
201              if ((uint16_t)(path_right - box_x) >= STEP_PIXELS) {
202                  box_x = (uint16_t)(box_x + STEP_PIXELS);
203              } else {
204                  box_x = path_right;
205                  direction = MOVE_DOWN;
206              }
207              break;
208          case MOVE_DOWN:
209              if ((uint16_t)(path_bottom - box_y) >= STEP_PIXELS) {
210                  box_y = (uint16_t)(box_y + STEP_PIXELS);
211              } else {
212                  box_y = path_bottom;
213                  direction = MOVE_LEFT;
214              }
215              break;
216          case MOVE_LEFT:
217              if ((uint16_t)(box_x - path_left) >= STEP_PIXELS) {
218                  box_x = (uint16_t)(box_x - STEP_PIXELS);
219              } else {
220                  box_x = path_left;
221                  direction = MOVE_UP;
222              }
223              break;
224          case MOVE_UP:
225          default:
226              if ((uint16_t)(box_y - path_top) >= STEP_PIXELS) {
227                  box_y = (uint16_t)(box_y - STEP_PIXELS);
228              } else {
229                  box_y = path_top;
230                  direction = MOVE_RIGHT;
231              }
232              break;
233          }
234
235          int32_t next_pixel_x = (int32_t)pixel_x + pixel_dx;
236          int32_t next_pixel_y = (int32_t)pixel_y + pixel_dy;
237
238          if (next_pixel_x < 0) {
239              next_pixel_x = 0;
240              pixel_dx = (int16_t)(-pixel_dx);
241          } else if (next_pixel_x >= (int32_t)DISPLAY_WIDTH) {
242              next_pixel_x = (int32_t)DISPLAY_WIDTH - 1;
243              pixel_dx = (int16_t)(-pixel_dx);
244          }
245
246          if (next_pixel_y < 0) {
247              next_pixel_y = 0;
248              pixel_dy = (int16_t)(-pixel_dy);
249          } else if (next_pixel_y >= (int32_t)DISPLAY_HEIGHT) {
250              next_pixel_y = (int32_t)DISPLAY_HEIGHT - 1;
251              pixel_dy = (int16_t)(-pixel_dy);
252          }
253
254          pixel_x = (uint16_t)next_pixel_x;
255          pixel_y = (uint16_t)next_pixel_y;
256          frame_count++;
257
258          usleep(FRAME_DELAY_MS * 1000U);
259      }
260
261      /* Unreachable in this demo */
262      gfx_framebuffer_unbind(&framebuffer);
263      free(fb_storage);
264      hal_display_deinitialize();
265
266      return EXIT_SUCCESS;
267  }
